@Test
public void testIteratorMultipleHasNextCalls() throws IOException {
    final String threeRows = "1\n2\n3\n";
    CSVParser parser = CSVFormat.DEFAULT.parse(new StringReader(threeRows));
    Iterator<CSVRecord> iter = parser.iterator();

    assertTrue(iter.hasNext());
    assertTrue(iter.hasNext());
    assertTrue(iter.hasNext());
    CSVRecord record = iter.next();
    assertEquals("1", record.get(0));

    assertTrue(iter.hasNext());
    assertTrue(iter.hasNext());
    record = iter.next();
    assertEquals("2", record.get(0));

    assertTrue(iter.hasNext());
    record = iter.next();
    assertEquals("3", record.get(0));

    assertFalse(iter.hasNext());
    assertFalse(iter.hasNext());
}

@Test
public void testIteratorNextWithoutHasNext() throws IOException {
    final String twoRows = "a\nb\n";
    CSVParser parser = CSVFormat.DEFAULT.parse(new StringReader(twoRows));
    Iterator<CSVRecord> iter = parser.iterator();

    CSVRecord record1 = iter.next();
    assertEquals("a", record1.get(0));

    CSVRecord record2 = iter.next();
    assertEquals("b", record2.get(0));

    try {
        iter.next();
        fail("Expected NoSuchElementException");
    } catch (NoSuchElementException e) {
        // Expected
    }
}

@Test
public void testIteratorMixedHasNextAndNext() throws IOException {
    final String fourRows = "x\ny\nz\nw\n";
    CSVParser parser = CSVFormat.DEFAULT.parse(new StringReader(fourRows));
    Iterator<CSVRecord> iter = parser.iterator();

    assertTrue(iter.hasNext());
    CSVRecord record1 = iter.next();
    assertEquals("x", record1.get(0));

    CSVRecord record2 = iter.next();
    assertEquals("y", record2.get(0));

    assertTrue(iter.hasNext());
    CSVRecord record3 = iter.next();
    assertEquals("z", record3.get(0));

    assertTrue(iter.hasNext());
    assertTrue(iter.hasNext());
    CSVRecord record4 = iter.next();
    assertEquals("w", record4.get(0));

    assertFalse(iter.hasNext());
}
